const { exec } = require('child_process');
const { promisify } = require('util');
const execAsync = promisify(exec);

const now = new Date();
const pad = n => String(n).padStart(2, '0');
const timestamp = `${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}_${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;
const outputPath = `C:\\AI\\MyOdin\\M2\\screenshots_\\screen_${timestamp}.png`;

const command = `python "C:\\AI\\MyOdin\\sdk\\vision_tool.py" --output "${outputPath}"`;

try {
  const { stdout, stderr } = await execAsync(command, { shell: 'powershell.exe' });
  return [{ json: { success: true, outputPath, stdout, stderr } }];
} catch (err) {
  return [{ json: { success: false, error: err.message, outputPath } }];
}
